#include <stdio.h>
#include <string.h>
int main(){
    int T;
    if(scanf("%d\n", &T)!=1) return 0;
    char buf[105];
    while(T--){
        if(!fgets(buf, sizeof(buf), stdin)) buf[0]='\0';
        size_t len = strlen(buf);
        if(len && buf[len-1]=='\n') buf[len-1]=0;
        int cnt=0;
        for(int i=0; buf[i]; ++i){
            char c = buf[i];
            if(c>='A' && c<='Z') c = c - 'A' + 'a';
            if(c=='a'||c=='e'||c=='i'||c=='o'||c=='u') cnt++;
        }
        printf("%d\n", cnt);
    }
    return 0;
}

