using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0; string line; getline(cin,line); // consume endline after T
    while(T--){
        getline(cin,line);
        int cnt=0;
        for(char ch: line){
            char c = tolower(static_cast<unsigned char>(ch));
            if(c=='a'||c=='e'||c=='i'||c=='o'||c=='u') cnt++;
        }
        cout<<cnt<<"\n";
    }
    return 0;
}

code.Java:
import java.io.*;
public class Main{
    public static void main(String[] args) throws IOException{
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String first = br.readLine();
        if(first==null || first.isEmpty()) return;
        int T = Integer.parseInt(first.trim());
        StringBuilder out = new StringBuilder();
        for(int i=0;i<T;i++){
            String s = br.readLine();
            if(s==null) s = "";
            int cnt = 0;
            for(int j=0;j<s.length();j++){
                char c = Character.toLowerCase(s.charAt(j));
                if(c=='a'||c=='e'||c=='i'||c=='o'||c=='u') cnt++;
            }
            out.append(cnt).append('\n');
        }
        System.out.print(out.toString());
    }
}

