const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').split('\n');
let idx = 0;
const T = parseInt((lines[idx++] || '').trim(), 10) || 0;
let results = [];
for(let t = 0; t < T; t++){
    const s = lines[idx++] || '';
    let cnt = 0;
    for(let i = 0; i < s.length; i++){
        const ch = s[i].toLowerCase();
        if(ch === 'a' || ch === 'e' || ch === 'i' || ch === 'o' || ch === 'u') cnt++;
    }
    results.push(cnt.toString());
}
console.log(results.join('\n'));

